// islands/live-chart.island.tsx
export const howl = { ssr: false };

export default function LiveChart() {
  // Never runs on the server. Empty markers in the HTML;
  // client mounts the real component after JS loads.
  const data = useLiveData();
  return <Chart data={data} />;
}

