// islands/page.island.tsx
import { ClientOnly } from "@hushkey/howl";
import { Toaster } from "sonner";

export default function PageIsland() {
  return (
    <div>
      <h1>SSR'd heading</h1>
      <ClientOnly>{() => <Toaster />}</ClientOnly>
    </div>
  );
}

import { IS_BROWSER, IS_SERVER } from "@hushkey/howl";

// safe default for SSR, real value on the client
const stored = IS_BROWSER ? localStorage.getItem("prefs") : null;

// signal with a safe initial value
const theme = signal("light");
if (IS_BROWSER) theme.value = localStorage.getItem("theme") ?? "light";

import { signal } from "@preact/signals";

const count = signal(0);

export default function ReactiveCounter() {
  return (
    <button onClick={() => count.value++}>
      Clicked {count} times
    </button>
  );
}
